import{_ as t,o as i,c as p,ag as a}from"./chunks/framework.DXGyWiRo.js";const e="/media/202508/2025-08-13_104713_6523400.7898041542893726.png",r="/media/202508/2025-08-13_104741_4413030.7020920035226506.png",n="/media/202508/2025-08-13_105013_4621220.4007163204859149.png",o="/media/202508/2025-08-13_105124_8772430.7791866593553918.png",_="/media/202508/2025-08-13_105841_0433240.84403469293343.png",s="/media/202508/2025-08-13_105814_5914030.5764349495448472.png",c="/media/202508/2025-08-13_112026_4481340.350957902420055.png",m="/media/202508/2025-08-13_112359_3670040.29537052212661086.png",d="/media/202508/2025-08-13_111542_7123050.14264962523579594.png",u="/media/202508/2025-08-13_111616_1379470.8687966846359003.png",k=JSON.parse('{"title":"回复角色配置","description":"","frontmatter":{"title":"回复角色配置"},"headers":[],"relativePath":"app-config/reply-role.md","filePath":"app-config/reply-role.md","lastUpdated":null}'),g={name:"app-config/reply-role.md"};function h(f,l,b,q,I,P){return i(),p("div",null,[...l[0]||(l[0]=[a('<p>回复角色配置概述</p><p>回复角色配置是AIUI极速超拟人交互类应用提供的配置项目。该配置项，一是展示极速链路当前在基础配置中配置的回复角色相关信息，一是提供全链路语音合成服务开关和发音人选配。其中：</p><h2 id="回复角色展示" tabindex="-1">回复角色展示 <a class="header-anchor" href="#回复角色展示" aria-label="Permalink to &quot;回复角色展示&quot;">​</a></h2><p>当在基础配置中选择对应的角色时（官方或自定义），下面配置中将展示该角色的基础属性信息。</p><p><img src="'+e+'" alt="" title="null"></p><p><img src="'+r+'" alt="" title="null"></p><h2 id="合成开关" tabindex="-1">合成开关 <a class="header-anchor" href="#合成开关" aria-label="Permalink to &quot;合成开关&quot;">​</a></h2><p>该配置项（角色发音人）开关代表全链路语义后合成能力开关，当打开配置项后。每次对话，AIUI云服务将大模型回复的内容根据选配的发音人进行云端合成，下发合成音频数据。</p><p><img src="'+n+'" alt="" title="null"></p><h2 id="音色更换" tabindex="-1">音色更换 <a class="header-anchor" href="#音色更换" aria-label="Permalink to &quot;音色更换&quot;">​</a></h2><p>在发音人图标后点击“更换”，跳转的发音人选择窗口可以进行发音人选择。发音人整体分两大类：官方发音人和声音复刻。</p><p><strong>官方发音人</strong>选型可以通过下面两个维度来进行筛选：</p><ul><li>年龄段 <ul><li>成人女</li><li>成人男</li><li>儿童女</li><li>儿童男</li></ul></li><li>类型 <ul><li>普通</li><li>超拟人</li><li>极速超拟人</li></ul></li></ul><p><strong>声音复刻</strong>类型发音人，开发者可以在回复角色创建页面中进行自定义生成。</p><p>其中极速超拟人与超拟人发音人的区别在于，极速超拟人发音人支持流式合成【即单次合成时，合成文本支持分段流式发送】。</p><p><img src="'+o+'" alt="" title="null"></p><p><img src="'+_+'" alt="" title="null"></p><p><img src="'+s+'" alt="" title="null"></p><p>开发者在选择发音人时，还可以通过发音人图标右上角了解当前发音人vcn取值，在端侧做主动合成时可以直接使用。</p><p><img src="'+c+'" alt="" title="null"></p><p>另外发音人图标上的“授”字图标代表授权信息，蓝色代表该发音人已授权，可以直接选配使用，橙色代表该发音人未授权，需要联系讯飞授权后才可使用。</p><p>温馨提示</p><p>AIUI极速交互类应用免费全开放了超拟人和极速超拟人发音人，开发者可直接免费选配使用</p><p><img src="'+m+'" alt="" title="null"></p><h2 id="发音人试听" tabindex="-1">发音人试听 <a class="header-anchor" href="#发音人试听" aria-label="Permalink to &quot;发音人试听&quot;">​</a></h2><p>该能力是提供给开发者在线试听发音人音色的，试听方式有两种：</p><ul><li>在发音人选择界面直接点击播放按钮进行试听</li><li>选择发音人后自定义合成文本、调节合成参数进行合成试听</li></ul><p><img src="'+d+'" alt="" title="null"></p><p><img src="'+u+'" alt="" title="null"></p>',29)])])}const A=t(g,[["render",h]]);export{k as __pageData,A as default};
